diff --git a/llvm/include/llvm/Analysis/StackSafetyAnalysis.h b/llvm/include/llvm/Analysis/StackSafetyAnalysis.h
index b7b816fa4021e..b91b45d0f6752 100644
--- a/llvm/include/llvm/Analysis/StackSafetyAnalysis.h
+++ b/llvm/include/llvm/Analysis/StackSafetyAnalysis.h
@@ -79,6 +79,11 @@ class StackSafetyGlobalInfo {
   // during its lifetime.
   bool isSafe(const AllocaInst &AI) const;

+  // Returns true if the alloca's address is passed to a function call.
+  // This is relevant for ASan which needs the caller to initialize shadow
+  // memory when addresses escape to callees.
+  bool addressEscapesToCall(const AllocaInst &AI) const;
+
   // Returns true if the instruction can be proven to do only two types of
   // memory accesses:
   //  (1) live stack locations in-bounds or
diff --git a/llvm/lib/Analysis/StackSafetyAnalysis.cpp b/llvm/lib/Analysis/StackSafetyAnalysis.cpp
index fbe74d21c7199..06f9d5f19bc67 100644
--- a/llvm/lib/Analysis/StackSafetyAnalysis.cpp
+++ b/llvm/lib/Analysis/StackSafetyAnalysis.cpp
@@ -998,6 +998,18 @@ bool StackSafetyGlobalInfo::isSafe(const AllocaInst &AI) const {
   return Info.SafeAllocas.count(&AI);
 }

+bool StackSafetyGlobalInfo::addressEscapesToCall(const AllocaInst &AI) const {
+  const auto &Info = getInfo();
+  const Function *F = AI.getFunction();
+  auto FnIt = Info.Info.find(F);
+  if (FnIt == Info.Info.end())
+    return true; // Conservative: assume escapes if we don't have info
+  auto AllocaIt = FnIt->second.Allocas.find(&AI);
+  if (AllocaIt == FnIt->second.Allocas.end())
+    return true; // Conservative: assume escapes if we don't have info
+  return !AllocaIt->second.Calls.empty();
+}
+
 bool StackSafetyGlobalInfo::stackAccessIsSafe(const Instruction &I) const {
   const auto &Info = getInfo();
   return Info.UnsafeAccesses.find(&I) == Info.UnsafeAccesses.end();
diff --git a/llvm/lib/Transforms/Instrumentation/AddressSanitizer.cpp b/llvm/lib/Transforms/Instrumentation/AddressSanitizer.cpp
index 3ea290a77b18b..424d6ea754eed 100644
--- a/llvm/lib/Transforms/Instrumentation/AddressSanitizer.cpp
+++ b/llvm/lib/Transforms/Instrumentation/AddressSanitizer.cpp
@@ -1447,8 +1447,9 @@ bool AddressSanitizer::isInterestingAlloca(const AllocaInst &AI) {
        !AI.isUsedWithInAlloca() &&
        // swifterror allocas are register promoted by ISel
        !AI.isSwiftError() &&
-       // safe allocas are not interesting
-       !(SSGI && SSGI->isSafe(AI)));
+       // safe allocas are not interesting, but for ASan we also need to ensure
+       // the address doesn't escape to calls (callee may access shadow memory)
+       !(SSGI && SSGI->isSafe(AI) && !SSGI->addressEscapesToCall(AI)));

   It->second = IsInteresting;
   return IsInteresting;

